/* MLA Litigation Desk — shared.js */
(function(){
const LSM="data:image/png;base64,";
const LLG=window.LLG="data:image/png;base64,";

/* CSS */
var s=document.createElement('style');
s.textContent='@import url(\'https://fonts.googleapis.com/css2?family=Cinzel:wght@400;500;600;700&family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;0,600;1,300;1,400;1,600&display=swap\');'
+'*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}'
+':root{--bg:#140c06;--bg2:#111116;--bg3:#161620;--gold:#c9a444;--gold2:#e4c46e;--cream:#e8dfc8;--muted:#8a8070;--bdr:rgba(201,164,68,0.18);--red:#d45f5f;--green:#5a9f72;--blue:#5b8fd5;--yellow:#d4a020}'
+'html,body{height:100%;background:#140c06;color:#e8dfc8;font-family:\'Cormorant Garamond\',Georgia,serif}'
+'::-webkit-scrollbar{width:4px}::-webkit-scrollbar-track{background:transparent}::-webkit-scrollbar-thumb{background:rgba(201,164,68,.25);border-radius:2px}'
+'@keyframes fu{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:none}}'
+'@keyframes fi{from{opacity:0}to{opacity:1}}'
+'@keyframes pulse{0%,100%{opacity:1}50%{opacity:.3}}'
+'.anim{animation:fu .35s ease both}.ain{animation:fi .28s ease both}'
+'.ni{transition:all .18s;cursor:pointer;border-left:2px solid transparent}'
+'.ni:hover{background:rgba(201,164,68,.07)!important}'
+'.ni.on{background:rgba(201,164,68,.13)!important;border-left-color:#c9a444!important;color:#c9a444!important}'
+'.rh{cursor:pointer}.rh:hover{background:rgba(255,255,255,.025)!important}'
+'.ch:hover{border-color:rgba(201,164,68,.4)!important}'
+'.gh:hover{border-color:#c9a444!important;color:#c9a444!important}'
+'input,select,textarea{outline:none;font-family:\'Cormorant Garamond\',Georgia,serif}'
+'input:focus,textarea:focus,select:focus{border-color:rgba(201,164,68,.5)!important}'
+'button{cursor:pointer}'
+'.g2{display:grid;grid-template-columns:1fr 1fr;gap:20px}'
+'.g4{display:grid;grid-template-columns:repeat(4,1fr);gap:13px}'
+'.ga{display:grid;grid-template-columns:repeat(auto-fit,minmax(155px,1fr));gap:12px}'
+'@media(max-width:768px){.g2{grid-template-columns:1fr}.g4{grid-template-columns:1fr 1fr}.ga{grid-template-columns:1fr 1fr}.mob-show{display:flex!important}.desk-hide{display:none!important}}';
document.head.appendChild(s);

/* renderSidebar */
window.renderSidebar=function(activeId){
  var gold='#c9a444',muted='#8a8070',cream='#e8dfc8',bdr='rgba(201,164,68,0.18)';

  var btn=document.createElement('button');
  btn.className='mob-show';
  btn.style.cssText='display:none;position:fixed;top:13px;left:13px;z-index:200;background:#111116;border:1px solid '+bdr+';color:'+gold+';padding:8px 10px;font-size:17px;line-height:1;cursor:pointer';
  btn.innerHTML='☰';
  document.body.appendChild(btn);

  var ov=document.createElement('div');
  ov.style.cssText='display:none;position:fixed;inset:0;background:rgba(0,0,0,.6);z-index:99';
  document.body.appendChild(ov);

  var sb=document.createElement('div');
  sb.id='_sidebar';

  var isMob=window.innerWidth<=768;
  sb.style.cssText='width:220px;flex-shrink:0;background:#0b0703;border-right:1px solid '+bdr+';display:flex;flex-direction:column;height:100vh;'+(isMob?'position:fixed;top:0;left:0;z-index:100;transform:translateX(-100%);transition:transform .25s':'');

  var header='<div style="padding:20px 18px 15px;border-bottom:1px solid '+bdr+'">'
    +'<div style="display:flex;align-items:center;gap:11px;margin-bottom:9px">'
    +'<img src="'+LSM+'" alt="MLA" style="width:44px;height:44px;border-radius:50%;border:1px solid '+bdr+';flex-shrink:0">'
    +'<div><div style="font-family:Cinzel,serif;font-size:.78rem;color:'+cream+';letter-spacing:.05em;line-height:1.2">Litigation Desk</div>'
    +'<div style="font-family:Cinzel,serif;font-size:.49rem;letter-spacing:.18em;text-transform:uppercase;color:'+gold+';margin-top:2px">Mian Law Associates</div></div></div>'
    +'<div style="font-size:.69rem;color:'+muted+'">Adv. Mian Aqil Nawaz · HC</div></div>';

  var nav='<nav style="flex:1;padding:12px 0;overflow-y:auto"><a href="dashboard.html" class="ni" data-id="dashboard" style="display:flex;align-items:center;gap:12px;padding:11px 20px;text-decoration:none"><span style="font-size:15px">⊡</span><span style="font-family:Cinzel,serif;font-size:.57rem;letter-spacing:.12em;text-transform:uppercase">Dashboard</span></a><a href="cases.html" class="ni" data-id="cases" style="display:flex;align-items:center;gap:12px;padding:11px 20px;text-decoration:none"><span style="font-size:15px">⚖</span><span style="font-family:Cinzel,serif;font-size:.57rem;letter-spacing:.12em;text-transform:uppercase">Case Records</span></a><a href="calendar.html" class="ni" data-id="calendar" style="display:flex;align-items:center;gap:12px;padding:11px 20px;text-decoration:none"><span style="font-size:15px">◫</span><span style="font-family:Cinzel,serif;font-size:.57rem;letter-spacing:.12em;text-transform:uppercase">Court Diary</span></a><a href="clients.html" class="ni" data-id="clients" style="display:flex;align-items:center;gap:12px;padding:11px 20px;text-decoration:none"><span style="font-size:15px">◈</span><span style="font-family:Cinzel,serif;font-size:.57rem;letter-spacing:.12em;text-transform:uppercase">Clients</span></a><a href="finance.html" class="ni" data-id="finance" style="display:flex;align-items:center;gap:12px;padding:11px 20px;text-decoration:none"><span style="font-size:15px">₨</span><span style="font-family:Cinzel,serif;font-size:.57rem;letter-spacing:.12em;text-transform:uppercase">Finance</span></a><a href="reminders.html" class="ni" data-id="reminders" style="display:flex;align-items:center;gap:12px;padding:11px 20px;text-decoration:none"><span style="font-size:15px">◉</span><span style="font-family:Cinzel,serif;font-size:.57rem;letter-spacing:.12em;text-transform:uppercase">Reminders</span></a></nav>';

  var footer='<div style="padding:14px 20px;border-top:1px solid '+bdr+'">'
    +'<div style="font-family:Cinzel,serif;font-size:.5rem;letter-spacing:.14em;text-transform:uppercase;color:#4a4030;margin-bottom:8px">Chamber 39 · District Courts</div>'
    +'<div class="ni" onclick="logout()" style="display:flex;align-items:center;gap:9px;padding:7px 0;color:'+muted+'">'
    +'<span style="font-size:14px">↩</span>'
    +'<span style="font-family:Cinzel,serif;font-size:.54rem;letter-spacing:.12em;text-transform:uppercase">Sign Out</span></div></div>';

  sb.innerHTML=header+nav+footer;

  // mark active
  var links=sb.querySelectorAll('.ni[data-id]');
  links.forEach(function(a){
    if(a.getAttribute('data-id')===activeId){a.classList.add('on');a.style.color=gold;}
    else{a.style.color=muted;}
  });

  document.body.insertBefore(sb, document.body.firstChild);

  if(isMob){
    var open=function(){sb.style.transform='translateX(0)';ov.style.display='block';};
    var close=function(){sb.style.transform='translateX(-100%)';ov.style.display='none';};
    btn.onclick=open;
    ov.onclick=close;
  }
};

/* showToast */
window.showToast=function(msg,type){
  var col=type==='error'?'#d45f5f':'#5a9f72';
  var t=document.createElement('div');
  t.style.cssText='position:fixed;bottom:24px;right:24px;z-index:9999;background:#111116;border:1px solid '+col+';color:'+col+';font-family:Cinzel,serif;font-size:.6rem;letter-spacing:.14em;text-transform:uppercase;padding:12px 20px;animation:fu .3s ease both';
  t.textContent=msg;
  document.body.appendChild(t);
  setTimeout(function(){t.remove();},3000);
};

/* initPage */
window.initPage=function(activeId){
  requireAuth();
  renderSidebar(activeId);
  return getCases();
};
})();
